import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as r,c as o,a,b as e,e as s,d as c}from"./app-b1c018be.js";const l="/assets/image-20231114221905562-b8eea716.png",d="/assets/image-20231114222307835-e1aefd00.png",p="/assets/image-20231114222335819-92d4511f.png",g={},m=c('<h1 id="多级缓存" tabindex="-1"><a class="header-anchor" href="#多级缓存" aria-hidden="true">#</a> 多级缓存</h1><h2 id="_1-什么是多级缓存" tabindex="-1"><a class="header-anchor" href="#_1-什么是多级缓存" aria-hidden="true">#</a> 1.什么是多级缓存</h2><p>传统的缓存策略一般是请求到达Tomcat后，先查询Redis，如果未命中则查询数据库，如图：</p><figure><img src="'+l+'" alt="image-20231114221905562" tabindex="0" loading="lazy"><figcaption>image-20231114221905562</figcaption></figure><p>存在下面的问题：</p><ul><li><p>请求要经过Tomcat处理，Tomcat的性能成为整个系统的瓶颈</p></li><li><p>Redis缓存失效时，会对数据库产生冲击</p></li></ul><p>多级缓存就是充分利用请求处理的每个环节，分别添加缓存，减轻Tomcat压力，提升服务性能：</p><ul><li>浏览器访问静态资源时，优先读取浏览器本地缓存</li><li>访问非静态资源（ajax查询数据）时，访问服务端</li><li>请求到达Nginx后，优先读取Nginx本地缓存</li><li>如果Nginx本地缓存未命中，则去直接查询Redis（不经过Tomcat）</li><li>如果Redis查询未命中，则查询Tomcat</li><li>请求进入Tomcat后，优先查询JVM进程缓存</li><li>如果JVM进程缓存未命中，则查询数据库</li></ul><figure><img src="'+d+'" alt="image-20231114222307835" tabindex="0" loading="lazy"><figcaption>image-20231114222307835</figcaption></figure><p>在多级缓存架构中，Nginx内部需要编写本地缓存查询、Redis查询、Tomcat查询的业务逻辑，因此这样的nginx服务不再是一个<strong>反向代理服务器</strong>，而是一个编写<strong>业务的Web服务器了</strong>。</p><p>因此这样的业务Nginx服务也需要搭建集群来提高并发，再有专门的nginx服务来做反向代理，另外，我们的Tomcat服务将来也会部署为集群模式:</p><figure><img src="'+p+'" alt="image-20231114222335819" tabindex="0" loading="lazy"><figcaption>image-20231114222335819</figcaption></figure><p>可见，多级缓存的关键有两个：</p><ul><li><p>一个是在nginx中编写业务，实现nginx本地缓存、Redis、Tomcat的查询</p></li><li><p>另一个就是在Tomcat中实现JVM进程缓存</p></li></ul><p>其中Nginx编程则会用到OpenResty框架结合Lua这样的语言。</p><p><strong>这也是今天课程的难点和重点。</strong></p><h2 id="_2-jvm进程缓存" tabindex="-1"><a class="header-anchor" href="#_2-jvm进程缓存" aria-hidden="true">#</a> 2.JVM进程缓存</h2><p>为了演示多级缓存的案例，我们先准备一个商品查询的业务。</p><h2 id="_2-1-导入案例" tabindex="-1"><a class="header-anchor" href="#_2-1-导入案例" aria-hidden="true">#</a> 2.1.导入案例</h2>',19),_={href:"http://xn--fsqy8bm2rxoklxcuz1f.md",target:"_blank",rel:"noopener noreferrer"},h=a("h1",{id:"_2-1-1",tabindex:"-1"},[a("a",{class:"header-anchor",href:"#_2-1-1","aria-hidden":"true"},"#"),e(" 2.1.1")],-1);function f(x,u){const i=t("ExternalLinkIcon");return r(),o("div",null,[m,a("p",null,[e("参考课前资料的：《"),a("a",_,[e("案例导入说明.md"),s(i)]),e("》")]),h])}const N=n(g,[["render",f],["__file","02-多级缓存.html.vue"]]);export{N as default};
